from flask import Flask, render_template, redirect, request, session
from flask_oidc import OpenIDConnect
from cryptography.hazmat.primitives import serialization
from jwt import decode

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret'
app.config['OIDC_CLIENT_ID'] = 'your_client_id'
app.config['OIDC_CLIENT_SECRET'] = 'your_client_secret'
app.config['OIDC_PROVIDER_URL'] = 'your_provider_url'

oidc = OpenIDConnect(app)

@app.route('/')
def index():
    if oidc.is_authenticated():
        return render_template('index.html', user=session['user'])
    else:
        return redirect(oidc.authorize_redirect())

@oidc.callback_handler
def callback():
    token_response = oidc.callback()
    id_token = token_response.id_token
    decoded_token = decode(id_token, key=oidc.client.public_key.public_bytes(serialization.Encoding.PKCS1, serialization.PublicFormat.PKCS1), algorithms=['RS256'])
    session['user'] = decoded_token['sub']
    return redirect('/')

if __name__ == '__main__':
    app.run(debug=True)